async (params, browser) => {
  // Open model page
  await browser.open(`https://huggingface.co/${params.model_id}`)

  // Wait for page
  await browser.waitForSelector('h1, .prose, main', 15000)

  // Let page render
  await browser.wait(2500)

  // Scroll for model card
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(2000)

  // Extract model info
  const model_data = await browser.evaluate(`const title = document.querySelector('h1')?.textContent?.trim() || ''; const tags = Array.from(document.querySelectorAll('a[href*="/models?"]')).slice(0, 10).map(t => t.textContent.trim()); const dlEl = document.querySelector('[title*="download"], [title*="Download"]'); const downloads = dlEl?.textContent?.trim() || ''; const likesEl = document.querySelector('button[title*="Like"], button[title*="like"]'); const likes = likesEl?.textContent?.trim() || ''; const card = document.querySelector('.prose')?.innerText?.substring(0, 2000) || ''; return { model_id: '' + params.model_id + '', title, tags, downloads, likes, model_card_summary: card, url: window.location.href };`)

  return model_data
}
